function initiateModifyTimelockInterval(
  bytes4 functionSelector, uint256 newTimelockInterval, uint256 extraTime
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Ensure a timelock interval over eight weeks is not set on this function.
  if (functionSelector == this.modifyTimelockInterval.selector) {
    require(
      newTimelockInterval <= 8 weeks,
      "Timelock interval of modifyTimelockInterval cannot exceed eight weeks."
    );
  }

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.modifyTimelockInterval.selector,
    abi.encode(functionSelector, newTimelockInterval),
    extraTime
  );
}

function _verifyRecover(
  address account, bytes32 digest, bytes memory signature
) private pure {
  // Ensure the signature length is correct.
  require(
    signature.length == 65,
    "Must supply a single 65-byte signature when owner is not a contract."
  );

  // Divide the signature in r, s and v variables.
  bytes32 r;
  bytes32 s;
  uint8 v;
  assembly {
    r := mload(add(signature, 0x20))
    s := mload(add(signature, 0x40))
    v := byte(0, mload(add(signature, 0x60)))
  }

  require(
    uint256(s) <= _MAX_UNMALLEABLE_S,
    "Signature `s` value cannot be potentially malleable."
  );

  require(v == 27 || v == 28, "Signature `v` value not permitted.");

  require(account == ecrecover(digest, v, r, s), "Invalid signature.");
}

function _addPermissionsToRole(
    string memory role_,
    string memory resourceToAdd_,
    string[] memory permissionsToAdd_,
    bool allowed_
) internal {
    ARBACStorage storage $ = _getARBACStorage();

    DynamicSet.StringSet storage _resources = $.roleResources[role_][allowed_];
    DynamicSet.StringSet storage _permissions = $.rolePermissions[role_][allowed_][
        resourceToAdd_
    ];

    for (uint256 i = 0; i < permissionsToAdd_.length; ++i) {
        _permissions.add(permissionsToAdd_[i]);
    }

    _resources.add(resourceToAdd_);

    emit AddedPermissions(role_, resourceToAdd_, permissionsToAdd_, allowed_);
}

function _removePermissionsFromRole(
    string memory role_,
    string memory resourceToRemove_,
    string[] memory permissionsToRemove_,
    bool allowed_
) internal {
    ARBACStorage storage $ = _getARBACStorage();

    DynamicSet.StringSet storage _resources = $.roleResources[role_][allowed_];
    DynamicSet.StringSet storage _permissions = $.rolePermissions[role_][allowed_][
        resourceToRemove_
    ];

    for (uint256 i = 0; i < permissionsToRemove_.length; ++i) {
        _permissions.remove(permissionsToRemove_[i]);
    }

    if (_permissions.length() == 0) {
        _resources.remove(resourceToRemove_);
    }

    emit RemovedPermissions(role_, resourceToRemove_, permissionsToRemove_, allowed_);
}

function _isAllowed(
    string memory role_,
    string memory resource_,
    string memory permission_
) internal view returns (bool) {
    ARBACStorage storage $ = _getARBACStorage();

    mapping(string => DynamicSet.StringSet) storage _resources = $.rolePermissions[role_][
        true
    ];

    DynamicSet.StringSet storage _allAllowed = _resources[ALL_RESOURCE];
    DynamicSet.StringSet storage _allowed = _resources[resource_];

    return (_allAllowed.contains(ALL_PERMISSION) ||
        _allAllowed.contains(permission_) ||
        _allowed.contains(ALL_PERMISSION) ||
        _allowed.contains(permission_));
}

function _isDisallowed(
    string memory role_,
    string memory resource_,
    string memory permission_
) internal view returns (bool) {
    ARBACStorage storage $ = _getARBACStorage();

    mapping(string => DynamicSet.StringSet) storage _resources = $.rolePermissions[role_][
        false
    ];

    DynamicSet.StringSet storage _allDisallowed = _resources[ALL_RESOURCE];
    DynamicSet.StringSet storage _disallowed = _resources[resource_];

    return (_allDisallowed.contains(ALL_PERMISSION) ||
        _allDisallowed.contains(permission_) ||
        _disallowed.contains(ALL_PERMISSION) ||
        _disallowed.contains(permission_));
}

function _validateSignature(
    PackedUserOperation calldata userOp_,
    bytes32 userOpHash_
) internal virtual returns (uint256 validationData_) {
    // For gas estimation bundler sets signature as empty
    // and we need to avoid reverting in this case
    if (userOp_.signature.length < 65) {
        return SIG_VALIDATION_FAILED;
    }

    address recovered_ = ECDSA.recover(userOpHash_, userOp_.signature);

    if (recovered_ == address(this) || recovered_ == trustedExecutor()) {
        return SIG_VALIDATION_SUCCESS;
    }

    return SIG_VALIDATION_FAILED;
}

function redeem(
    uint256 assetType_,
    bytes calldata redeemDetails_,
    bytes calldata proof_
) external virtual {
    ABridgeStorage storage $ = _getABridgeStorage();

    if (!assetTypeSupported(assetType_)) revert HandlerDoesNotExist(assetType_);

    address handler_ = $.handlers.get(assetType_);

    bytes32 operationHash_ = IHandler(handler_).getOperationHash(
        this,
        $.network,
        redeemDetails_
    );

    _checkAndUpdateNonce(operationHash_);
    _checkSignatures(operationHash_, abi.decode(proof_, (bytes[])));

    handler_.functionDelegateCall(
        abi.encodeWithSelector(IHandler.redeem.selector, $.batcher, redeemDetails_)
    );
}

function _checkCorrectSigners(address[] memory signers_) internal view virtual {
    ABridgeStorage storage $ = _getABridgeStorage();

    uint256 bitMap_;

    for (uint256 i = 0; i < signers_.length; ++i) {
        address signer_ = signers_[i];

        if (!$.signers.contains(signer_)) revert InvalidSigner(signer_);

        // get the topmost byte for bloom filtering
        uint256 bitKey_ = 2 ** (uint256(uint160(signer_)) >> 152);

        if (bitMap_ & bitKey_ != 0) revert DuplicateSigner(signer_);

        bitMap_ |= bitKey_;
    }

    if (signers_.length < $.signaturesThreshold) revert ThresholdNotMet(signers_.length);
}

function avg(SD59x18 x, SD59x18 y) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    int256 yInt = y.unwrap();

    unchecked {
        // This operation is equivalent to `x / 2 +  y / 2`, and it can never overflow.
        int256 sum = (xInt >> 1) + (yInt >> 1);

        if (sum < 0) {
            // If at least one of x and y is odd, add 1 to the result, because shifting negative numbers to the right
            // rounds toward negative infinity. The right part is equivalent to `sum + (x % 2 == 1 || y % 2 == 1)`.
            assembly ("memory-safe") {
                result := add(sum, and(or(xInt, yInt), 1))
            }
        } else {
            // Add 1 if both x and y are odd to account for the double 0.5 remainder truncated after shifting.
            result = wrap(sum + (xInt & yInt & 1));
        }
    }
}

function exp(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();

    // Any input less than the threshold returns zero.
    // This check also prevents an overflow for very small numbers.
    if (xInt < uEXP_MIN_THRESHOLD) {
        return ZERO;
    }

    // This check prevents values greater than 192e18 from being passed to {exp2}.
    if (xInt > uEXP_MAX_INPUT) {
        revert Errors.PRBMath_SD59x18_Exp_InputTooBig(x);
    }

    unchecked {
        // Inline the fixed-point multiplication to save gas.
        int256 doubleUnitProduct = xInt * uLOG2_E;
        result = exp2(wrap(doubleUnitProduct / uUNIT));
    }
}

function pow(SD59x18 x, SD59x18 y) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    int256 yInt = y.unwrap();

    // If both x and y are zero, the result is `UNIT`. If just x is zero, the result is always zero.
    if (xInt == 0) {
        return yInt == 0 ? UNIT : ZERO;
    }
    // If x is `UNIT`, the result is always `UNIT`.
    else if (xInt == uUNIT) {
        return UNIT;
    }

    // If y is zero, the result is always `UNIT`.
    if (yInt == 0) {
        return UNIT;
    }
    // If y is `UNIT`, the result is always x.
    else if (yInt == uUNIT) {
        return x;
    }

    // Calculate the result using the formula.
    result = exp2(mul(log2(x), y));
}

function sqrt(SD59x18 x) pure returns (SD59x18 result) {
    int256 xInt = x.unwrap();
    if (xInt < 0) {
        revert Errors.PRBMath_SD59x18_Sqrt_NegativeInput(x);
    }
    if (xInt > uMAX_SD59x18 / uUNIT) {
        revert Errors.PRBMath_SD59x18_Sqrt_Overflow(x);
    }

    unchecked {
        // Multiply x by `UNIT` to account for the factor of `UNIT` picked up when multiplying two SD59x18 numbers.
        // In this case, the two numbers are both the square root.
        uint256 resultUint = Common.sqrt(uint256(xInt * uUNIT));
        result = wrap(int256(resultUint));
    }
}

function permit(address owner, PermitBatch memory permitBatch, bytes calldata signature) external {
    if (block.timestamp > permitBatch.sigDeadline) revert SignatureExpired(permitBatch.sigDeadline);

    // Verify the signer address from the signature.
    signature.verify(_hashTypedData(permitBatch.hash()), owner);

    address spender = permitBatch.spender;
    unchecked {
        uint256 length = permitBatch.details.length;
        for (uint256 i = 0; i < length; ++i) {
            _updateApproval(permitBatch.details[i], owner, spender);
        }
    }
}

function _transfer(address from, address to, uint160 amount, address token) private {
    PackedAllowance storage allowed = allowance[from][token][msg.sender];

    if (block.timestamp > allowed.expiration) revert AllowanceExpired(allowed.expiration);

    uint256 maxAmount = allowed.amount;
    if (maxAmount != type(uint160).max) {
        if (amount > maxAmount) {
            revert InsufficientAllowance(maxAmount);
        } else {
            unchecked {
                allowed.amount = uint160(maxAmount) - amount;
            }
        }
    }

    // Transfer the tokens from the from address to the recipient.
    ERC20(token).safeTransferFrom(from, to, amount);
}

function simplePermit2(
    ERC20 token,
    address owner,
    address spender,
    uint256 amount,
    uint256 deadline,
    uint8 v,
    bytes32 r,
    bytes32 s
) internal {
    (,, uint48 nonce) = PERMIT2.allowance(owner, address(token), spender);

    PERMIT2.permit(
        owner,
        IAllowanceTransfer.PermitSingle({
            details: IAllowanceTransfer.PermitDetails({
                token: address(token),
                amount: amount.toUint160(),
                // Use an unlimited expiration because it most
                // closely mimics how a standard approval works.
                expiration: type(uint48).max,
                nonce: nonce
            }),
            spender: spender,
            sigDeadline: deadline
        }),
        bytes.concat(r, s, bytes1(v))
    );
}

function hash(IAllowanceTransfer.PermitBatch memory permitBatch) internal pure returns (bytes32) {
    uint256 numPermits = permitBatch.details.length;
    bytes32[] memory permitHashes = new bytes32[](numPermits);
    for (uint256 i = 0; i < numPermits; ++i) {
        permitHashes[i] = _hashPermitDetails(permitBatch.details[i]);
    }
    return keccak256(
        abi.encode(
            _PERMIT_BATCH_TYPEHASH,
            keccak256(abi.encodePacked(permitHashes)),
            permitBatch.spender,
            permitBatch.sigDeadline
        )
    );
}

function hash(ISignatureTransfer.PermitBatchTransferFrom memory permit) internal view returns (bytes32) {
    uint256 numPermitted = permit.permitted.length;
    bytes32[] memory tokenPermissionHashes = new bytes32[](numPermitted);

    for (uint256 i = 0; i < numPermitted; ++i) {
        tokenPermissionHashes[i] = _hashTokenPermissions(permit.permitted[i]);
    }

    return keccak256(
        abi.encode(
            _PERMIT_BATCH_TRANSFER_FROM_TYPEHASH,
            keccak256(abi.encodePacked(tokenPermissionHashes)),
            msg.sender,
            permit.nonce,
            permit.deadline
        )
    );
}

function _execute(
    bytes32 mode,
    bytes calldata executionData,
    Call[] calldata calls,
    bytes calldata opData
) internal virtual {
    // Silence compiler warning on unused variables.
    mode = mode;
    executionData = executionData;
    // Very basic auth to only allow this contract to be called by itself.
    // Override this function to perform more complex auth with `opData`.
    if (opData.length == uint256(0)) {
        require(msg.sender == address(this));
        // Remember to return `_execute(calls, extraData)` when you override this function.
        return _execute(calls, bytes32(0));
    }
    revert(); // In your override, replace this with logic to operate on `opData`.
}

function eip712Domain()
        public
        view
        virtual
        returns (
            bytes1 fields,
            string memory name,
            string memory version,
            uint256 chainId,
            address verifyingContract,
            bytes32 salt,
            uint256[] memory extensions
        )
    {
        fields = hex"0f"; // `0b01111`.
        (name, version) = _domainNameAndVersion();
        chainId = block.chainid;
        verifyingContract = address(this);
        salt = salt; // `bytes32(0)`.
        extensions = extensions; // `new uint256[](0)`.
    }
